import React, { Component } from 'react'
import axios from 'axios'

export default class UploadFile extends Component {
    
    state = {
        setSelectedFile: null
    }

    changeHandler = (event) => {
        this.setState({
            setSelectedFile: event.target.files[0]
        })
    }

    submitHandler = () => {
        axios.post('http://localhost:80/api/testUpload.php', this.state.setSelectedFile)
        .then((res) => {
            console.log(res)
        })
    }
    render() {
        return (
            <div>
                Class Component
                <div>
                    <input type="file" onChange={this.changeHandler} />
                    <button type='submit' onClick={this.submitHandler} >Upload</button>
                </div>
            </div>
        )
    }
}
